+ (void)addEventWithType:(NSInteger)eventType data:(NSDictionary*)dic {
    [self addEventWithType:eventType data:dic urgent:false];
}

+ (void)addEventWithType:(NSInteger)eventType data:(NSDictionary*)dic urgent:(BOOL)isUrgent {
    WBEvent *event = [[WBEvent alloc] initWithType:eventType data:dic];
    event.urgent = isUrgent;
    [[WBEventManager defaultManager] addEvent:event];
}


+ (void)startReporting {
    NSLog(@"EventManager startReporting. hbrate:%d, lograte:%d", WBEventManager.defaultManager.heartbeatInterval, WBEventManager.defaultManager.reportInterval);
